// ── Mongoose Schema (minimal, uses raw collection access) ─────────────────────
const { Schema } = mongoose;

const MeasurementSchema = new Schema({ measurementName: String, value: String, unit: String });
const ProductEntrySchema = new Schema({
    productId: Schema.Types.ObjectId,
    productName: String,
    variantId: Schema.Types.ObjectId,
    variantName: String,
    quantity: Number,
    measurements: [MeasurementSchema],
    measuredAt: Date,
    qrGenerated: Boolean,
    qrGeneratedAt: Date,
});
const EmployeeMeasurementSchema = new Schema({
    employeeId: Schema.Types.ObjectId,
    employeeName: String,
    employeeUIN: String,
    gender: String,
    products: [ProductEntrySchema],
    noProductAssigned: Boolean,
    categoryMeasurements: [Schema.Types.Mixed],
    isCompleted: Boolean,
    completedAt: Date,
    remarks: String,
});
const BatchSchema = new Schema({
    employeeMeasurements: [EmployeeMeasurementSchema],
    measuredEmployees: Number,
    pendingEmployees: Number,
    completionRate: Number,
    totalMeasurements: Number,
    completedMeasurements: Number,
    pendingMeasurements: Number,
    updatedAt: Date,
}, { strict: false });

const MeasurementBatch = mongoose.model('measurementbatch', BatchSchema, 'measurements');

// ── Main ──────────────────────────────────────────────────────────────────────
async function main() {
    await mongoose.connect(MONGODB_URI);
    console.log('✅ Connected to MongoDB');

    const MEASURED_AT = new Date('2026-04-23T14:14:29.624Z');

    const newEmployeeMeasurements = MEASUREMENTS.map(emp => ({
        employeeId: new mongoose.Types.ObjectId(emp.employeeId),
        employeeName: emp.employeeName,
        employeeUIN: emp.employeeUIN,
        gender: emp.gender,
        products: [
            {
                productId: new mongoose.Types.ObjectId(emp.shirtProductId),
                productName: 'Executive to Managers Shirt',
                variantId: new mongoose.Types.ObjectId(emp.shirtVariantId),
                variantName: 'sky blue',
                quantity: 1,
                measurements: emp.shirtMeasurements,
                measuredAt: MEASURED_AT,
                qrGenerated: false,
                qrGeneratedAt: null,
            },
            {
                productId: new mongoose.Types.ObjectId(emp.trouserProductId),
                productName: 'Executive to Managers Trouser',
                variantId: new mongoose.Types.ObjectId(emp.trouserVariantId),
                variantName: 'Navy blue',
                quantity: 1,
                measurements: emp.trouserMeasurements,
                measuredAt: MEASURED_AT,
                qrGenerated: false,
                qrGeneratedAt: null,
            },
        ],
        noProductAssigned: false,
        categoryMeasurements: [],
        isCompleted: true,
        completedAt: MEASURED_AT,
        remarks: '',
    }));

    // ── Debug: verify the document actually exists before updating ──
    const existing = await MeasurementBatch.findOne(
        { _id: new mongoose.Types.ObjectId(BATCH_DOC_ID) },
        { _id: 1, name: 1, organizationName: 1 }
    ).lean();

    if (!existing) {
        const allBatches = await MeasurementBatch.find({}, { _id: 1, name: 1 }).lean();
        console.error('❌  Batch document NOT FOUND with _id:', BATCH_DOC_ID);
        console.error('   Batches in this collection:', JSON.stringify(allBatches, null, 2));
        console.error('   → Check that MONGODB_URI points to the correct database.');
        await mongoose.disconnect();
        process.exit(1);
    }

    console.log('✅ Found batch:', existing.name, '|', existing.organizationName);

    const result = await MeasurementBatch.updateOne(
        { _id: new mongoose.Types.ObjectId(BATCH_DOC_ID) },
        {
            $set: {
                employeeMeasurements: newEmployeeMeasurements,
                measuredEmployees: 112,
                pendingEmployees: 0,
                completionRate: 100,
                totalMeasurements: 224,
                completedMeasurements: 224,
                pendingMeasurements: 0,
                updatedAt: new Date(),
            }
        }
    );

    console.log(`✅ Matched: ${result.matchedCount}, Modified: ${result.modifiedCount}`);
    console.log(`✅ All 112 employee measurements updated successfully.`);
    await mongoose.disconnect();
}

main().catch(err => {
    console.error('❌ Error:', err);
    process.exit(1);
});